using UnityEngine;
using UnityEngine.UI;
using TMPro;

public class OptionsManager : MonoBehaviour
{
    [Header("Paneles")]
    public GameObject panelGeneral;
    public GameObject panelControles;

    [Header("Botones Pestañas")]
    public Button btnGeneral;
    public Button btnControles;

    [Header("General")]
    public Button btnPantallaCompleta;
    public Slider sliderVolumen;
    public TMP_Dropdown dropdownGraficos;
    public Button btnCerrar;

    // Colores pestañas
    private Color tabActivo = new Color(0.2f, 0.5f, 0.6f, 1f);
    private Color tabInactivo = new Color(0.15f, 0.15f, 0.15f, 1f);

    private bool isFullscreen = true;

    void Start()
    {
        // Pestañas
        btnGeneral.onClick.AddListener(() => MostrarPanel(0));
        btnControles.onClick.AddListener(() => MostrarPanel(1));

        // Pantalla completa
        btnPantallaCompleta.onClick.AddListener(TogglePantallaCompleta);

        // Volumen
        sliderVolumen.onValueChanged.AddListener(SetVolumen);

        // Graficos
        if (dropdownGraficos != null)
        {
            dropdownGraficos.ClearOptions();
            dropdownGraficos.AddOptions(new System.Collections.Generic.List<string> { "Bajo", "Medio", "Alto" });
            dropdownGraficos.onValueChanged.AddListener(SetGraficos);
        }

        // Cerrar
        if (btnCerrar != null)
        {
            btnCerrar.onClick.AddListener(CerrarOpciones);
        }

        // Cargar valores guardados
        CargarOpciones();

        // Mostrar General por defecto
        MostrarPanel(0);
    }

    void MostrarPanel(int index)
    {
        panelGeneral.SetActive(index == 0);
        panelControles.SetActive(index == 1);

        btnGeneral.GetComponent<Image>().color = index == 0 ? tabActivo : tabInactivo;
        btnControles.GetComponent<Image>().color = index == 1 ? tabActivo : tabInactivo;
    }

    void TogglePantallaCompleta()
    {
        isFullscreen = !isFullscreen;
        Screen.fullScreen = isFullscreen;
        PlayerPrefs.SetInt("Fullscreen", isFullscreen ? 1 : 0);

        var texto = btnPantallaCompleta.GetComponentInChildren<TextMeshProUGUI>();
        texto.text = isFullscreen ? "Pantalla Completa: ON" : "Pantalla Completa: OFF";
    }

    void SetVolumen(float valor)
    {
        AudioListener.volume = valor;
        PlayerPrefs.SetFloat("Volumen", valor);
    }

    void SetGraficos(int index)
    {
        QualitySettings.SetQualityLevel(index, true);
        PlayerPrefs.SetInt("Graficos", index);
    }

    void CargarOpciones()
    {
        // Fullscreen
        isFullscreen = PlayerPrefs.GetInt("Fullscreen", 1) == 1;
        Screen.fullScreen = isFullscreen;

        var texto = btnPantallaCompleta.GetComponentInChildren<TextMeshProUGUI>();
        texto.text = isFullscreen ? "Pantalla Completa: ON" : "Pantalla Completa: OFF";

        // Volumen
        sliderVolumen.value = PlayerPrefs.GetFloat("Volumen", 1f);
        AudioListener.volume = sliderVolumen.value;

        // Graficos
        int graficos = PlayerPrefs.GetInt("Graficos", 2); // Alto por defecto
        QualitySettings.SetQualityLevel(graficos, true);
        if (dropdownGraficos != null)
        {
            dropdownGraficos.value = graficos;
        }
    }

    public void CerrarOpciones()
    {
        PlayerPrefs.Save();
        gameObject.SetActive(false);
    }
}

using UnityEngine;
using UnityEngine.UI;
using UnityEditor;
using TMPro;

public class CreateOptionsPanel
{
    [MenuItem("Tools/Create Options Panel")]
    public static void Execute()
    {
        // Find Canvas
        Canvas canvas = Object.FindFirstObjectByType<Canvas>();
        if (canvas == null)
        {
            Debug.LogError("No Canvas found in scene!");
            return;
        }

        // ===== OPTIONS PANEL (root, starts inactive) =====
        GameObject optionsPanel = new GameObject("OptionsPanel", typeof(RectTransform), typeof(CanvasRenderer), typeof(Image), typeof(OptionsManager));
        optionsPanel.transform.SetParent(canvas.transform, false);
        optionsPanel.layer = LayerMask.NameToLayer("UI");

        RectTransform optionsRT = optionsPanel.GetComponent<RectTransform>();
        optionsRT.anchorMin = new Vector2(0.5f, 0.5f);
        optionsRT.anchorMax = new Vector2(0.5f, 0.5f);
        optionsRT.pivot = new Vector2(0.5f, 0.5f);
        optionsRT.sizeDelta = new Vector2(700, 500);
        optionsRT.anchoredPosition = Vector2.zero;

        Image optionsBg = optionsPanel.GetComponent<Image>();
        optionsBg.color = new Color(0.1f, 0.1f, 0.15f, 0.95f);

        // ===== TITLE =====
        GameObject titleObj = CreateTextObject("TitleText", optionsPanel.transform, "OPCIONES", 32, TextAlignmentOptions.Center, Color.white);
        RectTransform titleRT = titleObj.GetComponent<RectTransform>();
        titleRT.anchorMin = new Vector2(0, 1);
        titleRT.anchorMax = new Vector2(1, 1);
        titleRT.pivot = new Vector2(0.5f, 1);
        titleRT.sizeDelta = new Vector2(0, 50);
        titleRT.anchoredPosition = new Vector2(0, -10);

        // ===== TAB BAR =====
        GameObject tabBar = new GameObject("TabBar", typeof(RectTransform), typeof(HorizontalLayoutGroup));
        tabBar.transform.SetParent(optionsPanel.transform, false);
        tabBar.layer = LayerMask.NameToLayer("UI");

        RectTransform tabBarRT = tabBar.GetComponent<RectTransform>();
        tabBarRT.anchorMin = new Vector2(0, 1);
        tabBarRT.anchorMax = new Vector2(1, 1);
        tabBarRT.pivot = new Vector2(0.5f, 1);
        tabBarRT.sizeDelta = new Vector2(-40, 45);
        tabBarRT.anchoredPosition = new Vector2(0, -65);

        HorizontalLayoutGroup tabHLG = tabBar.GetComponent<HorizontalLayoutGroup>();
        tabHLG.spacing = 5;
        tabHLG.padding = new RectOffset(0, 0, 0, 0);
        tabHLG.childAlignment = TextAnchor.MiddleCenter;
        tabHLG.childForceExpandWidth = true;
        tabHLG.childForceExpandHeight = true;

        // Tab General
        GameObject btnGeneralObj = CreateButton("BtnGeneral", tabBar.transform, "General", new Color(0.2f, 0.5f, 0.6f, 1f));
        // Tab Controles
        GameObject btnControlesObj = CreateButton("BtnControles", tabBar.transform, "Controles", new Color(0.15f, 0.15f, 0.15f, 1f));

        // ===== PANEL GENERAL =====
        GameObject panelGeneral = new GameObject("PanelGeneral", typeof(RectTransform), typeof(VerticalLayoutGroup));
        panelGeneral.transform.SetParent(optionsPanel.transform, false);
        panelGeneral.layer = LayerMask.NameToLayer("UI");

        RectTransform pgRT = panelGeneral.GetComponent<RectTransform>();
        pgRT.anchorMin = new Vector2(0, 0);
        pgRT.anchorMax = new Vector2(1, 1);
        pgRT.pivot = new Vector2(0.5f, 0.5f);
        pgRT.offsetMin = new Vector2(30, 70); // left, bottom
        pgRT.offsetMax = new Vector2(-30, -120); // right, top

        VerticalLayoutGroup pgVLG = panelGeneral.GetComponent<VerticalLayoutGroup>();
        pgVLG.spacing = 20;
        pgVLG.padding = new RectOffset(10, 10, 10, 10);
        pgVLG.childAlignment = TextAnchor.UpperCenter;
        pgVLG.childForceExpandWidth = true;
        pgVLG.childForceExpandHeight = false;

        // --- Fullscreen Row ---
        GameObject fullscreenRow = CreateRow("FullscreenRow", panelGeneral.transform, 50);
        GameObject btnFullscreenObj = CreateButton("BtnPantallaCompleta", fullscreenRow.transform, "Pantalla Completa: ON", new Color(0.2f, 0.35f, 0.5f, 1f));
        RectTransform btnFSRT = btnFullscreenObj.GetComponent<RectTransform>();
        btnFSRT.anchorMin = Vector2.zero;
        btnFSRT.anchorMax = Vector2.one;
        btnFSRT.sizeDelta = Vector2.zero;
        btnFSRT.anchoredPosition = Vector2.zero;

        // --- Volume Row ---
        GameObject volRow = CreateRow("VolumeRow", panelGeneral.transform, 60);

        // Volume Label
        GameObject volLabel = CreateTextObject("VolumenLabel", volRow.transform, "Volumen", 20, TextAlignmentOptions.Left, Color.white);
        RectTransform volLabelRT = volLabel.GetComponent<RectTransform>();
        volLabelRT.anchorMin = new Vector2(0, 0);
        volLabelRT.anchorMax = new Vector2(0.3f, 1);
        volLabelRT.sizeDelta = Vector2.zero;
        volLabelRT.anchoredPosition = Vector2.zero;
        volLabelRT.offsetMin = new Vector2(5, 0);
        volLabelRT.offsetMax = Vector2.zero;

        // Volume Slider
        GameObject sliderObj = CreateSlider("SliderVolumen", volRow.transform);
        RectTransform sliderRT = sliderObj.GetComponent<RectTransform>();
        sliderRT.anchorMin = new Vector2(0.32f, 0.2f);
        sliderRT.anchorMax = new Vector2(0.98f, 0.8f);
        sliderRT.sizeDelta = Vector2.zero;
        sliderRT.anchoredPosition = Vector2.zero;

        // --- Graphics Row ---
        GameObject gfxRow = CreateRow("GraphicsRow", panelGeneral.transform, 60);

        // Graphics Label
        GameObject gfxLabel = CreateTextObject("GraficosLabel", gfxRow.transform, "Gráficos", 20, TextAlignmentOptions.Left, Color.white);
        RectTransform gfxLabelRT = gfxLabel.GetComponent<RectTransform>();
        gfxLabelRT.anchorMin = new Vector2(0, 0);
        gfxLabelRT.anchorMax = new Vector2(0.3f, 1);
        gfxLabelRT.sizeDelta = Vector2.zero;
        gfxLabelRT.anchoredPosition = Vector2.zero;
        gfxLabelRT.offsetMin = new Vector2(5, 0);
        gfxLabelRT.offsetMax = Vector2.zero;

        // Graphics Dropdown
        GameObject dropdownObj = CreateDropdown("DropdownGraficos", gfxRow.transform);
        RectTransform dropdownRT = dropdownObj.GetComponent<RectTransform>();
        dropdownRT.anchorMin = new Vector2(0.32f, 0.15f);
        dropdownRT.anchorMax = new Vector2(0.98f, 0.85f);
        dropdownRT.sizeDelta = Vector2.zero;
        dropdownRT.anchoredPosition = Vector2.zero;

        // ===== PANEL CONTROLES =====
        GameObject panelControles = new GameObject("PanelControles", typeof(RectTransform), typeof(VerticalLayoutGroup));
        panelControles.transform.SetParent(optionsPanel.transform, false);
        panelControles.layer = LayerMask.NameToLayer("UI");

        RectTransform pcRT = panelControles.GetComponent<RectTransform>();
        pcRT.anchorMin = new Vector2(0, 0);
        pcRT.anchorMax = new Vector2(1, 1);
        pcRT.pivot = new Vector2(0.5f, 0.5f);
        pcRT.offsetMin = new Vector2(30, 70);
        pcRT.offsetMax = new Vector2(-30, -120);

        VerticalLayoutGroup pcVLG = panelControles.GetComponent<VerticalLayoutGroup>();
        pcVLG.spacing = 10;
        pcVLG.padding = new RectOffset(10, 10, 20, 10);
        pcVLG.childAlignment = TextAnchor.UpperCenter;
        pcVLG.childForceExpandWidth = true;
        pcVLG.childForceExpandHeight = false;

        GameObject controlsText = CreateTextObject("ControlsInfo", panelControles.transform, "Controles del juego:\n\nClick izquierdo - Seleccionar carta\nClick derecho - Cancelar", 18, TextAlignmentOptions.TopLeft, new Color(0.8f, 0.8f, 0.8f, 1f));
        LayoutElement ctLE = controlsText.AddComponent<LayoutElement>();
        ctLE.preferredHeight = 200;

        panelControles.SetActive(false);

        // ===== CLOSE BUTTON =====
        GameObject btnCerrarObj = CreateButton("BtnCerrar", optionsPanel.transform, "X", new Color(0.7f, 0.15f, 0.15f, 1f));
        RectTransform cerrarRT = btnCerrarObj.GetComponent<RectTransform>();
        cerrarRT.anchorMin = new Vector2(1, 1);
        cerrarRT.anchorMax = new Vector2(1, 1);
        cerrarRT.pivot = new Vector2(1, 1);
        cerrarRT.sizeDelta = new Vector2(45, 45);
        cerrarRT.anchoredPosition = new Vector2(-5, -5);

        TextMeshProUGUI cerrarText = btnCerrarObj.GetComponentInChildren<TextMeshProUGUI>();
        if (cerrarText != null)
        {
            cerrarText.fontSize = 24;
            cerrarText.fontStyle = FontStyles.Bold;
        }

        // ===== WIRE UP OptionsManager =====
        OptionsManager om = optionsPanel.GetComponent<OptionsManager>();
        om.panelGeneral = panelGeneral;
        om.panelControles = panelControles;
        om.btnGeneral = btnGeneralObj.GetComponent<Button>();
        om.btnControles = btnControlesObj.GetComponent<Button>();
        om.btnPantallaCompleta = btnFullscreenObj.GetComponent<Button>();
        om.sliderVolumen = sliderObj.GetComponent<Slider>();
        om.dropdownGraficos = dropdownObj.GetComponent<TMP_Dropdown>();
        om.btnCerrar = btnCerrarObj.GetComponent<Button>();

        // ===== WIRE UP MainMenuManager =====
        MainMenuManager mmm = Object.FindFirstObjectByType<MainMenuManager>();
        if (mmm != null)
        {
            mmm.optionsPanel = optionsPanel;

            // Add onClick listener to OptionsButton
            GameObject optionsButton = GameObject.Find("Canvas/LeftPanel/OptionsButton");
            if (optionsButton != null)
            {
                Button optBtn = optionsButton.GetComponent<Button>();
                // We need to use UnityEditor to add persistent listener
                UnityEditor.Events.UnityEventTools.AddObjectPersistentListener<GameObject>(
                    optBtn.onClick, mmm.OnOptionsPressed);

                // Actually, let's use a simpler approach - add persistent void listener
                UnityEditor.Events.UnityEventTools.RemovePersistentListener(optBtn.onClick, 0);
            }

            EditorUtility.SetDirty(mmm);
        }

        // Start inactive
        optionsPanel.SetActive(false);

        // Mark scene dirty
        EditorUtility.SetDirty(optionsPanel);
        UnityEditor.SceneManagement.EditorSceneManager.MarkSceneDirty(
            UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene());

        Debug.Log("Options Panel created successfully!");
    }

    static GameObject CreateButton(string name, Transform parent, string text, Color bgColor)
    {
        GameObject btnObj = new GameObject(name, typeof(RectTransform), typeof(CanvasRenderer), typeof(Image), typeof(Button));
        btnObj.transform.SetParent(parent, false);
        btnObj.layer = LayerMask.NameToLayer("UI");

        Image img = btnObj.GetComponent<Image>();
        img.color = bgColor;
        img.sprite = AssetDatabase.GetBuiltinExtraResource<Sprite>("UI/Skin/UISprite.psd");
        img.type = Image.Type.Sliced;

        Button btn = btnObj.GetComponent<Button>();
        btn.targetGraphic = img;

        ColorBlock cb = btn.colors;
        cb.normalColor = Color.white;
        cb.highlightedColor = new Color(0.9f, 0.9f, 0.9f, 1f);
        cb.pressedColor = new Color(0.7f, 0.7f, 0.7f, 1f);
        btn.colors = cb;

        // Text child
        GameObject textObj = CreateTextObject("Text (TMP)", btnObj.transform, text, 18, TextAlignmentOptions.Center, Color.white);
        RectTransform textRT = textObj.GetComponent<RectTransform>();
        textRT.anchorMin = Vector2.zero;
        textRT.anchorMax = Vector2.one;
        textRT.sizeDelta = Vector2.zero;
        textRT.anchoredPosition = Vector2.zero;

        return btnObj;
    }

    static GameObject CreateTextObject(string name, Transform parent, string text, int fontSize, TextAlignmentOptions alignment, Color color)
    {
        GameObject textObj = new GameObject(name, typeof(RectTransform), typeof(CanvasRenderer), typeof(TextMeshProUGUI));
        textObj.transform.SetParent(parent, false);
        textObj.layer = LayerMask.NameToLayer("UI");

        TextMeshProUGUI tmp = textObj.GetComponent<TextMeshProUGUI>();
        tmp.text = text;
        tmp.fontSize = fontSize;
        tmp.alignment = alignment;
        tmp.color = color;

        // Try to load default TMP font
        TMP_FontAsset font = Resources.Load<TMP_FontAsset>("Fonts & Materials/LiberationSans SDF");
        if (font != null)
            tmp.font = font;

        return textObj;
    }

    static GameObject CreateRow(string name, Transform parent, float height)
    {
        GameObject row = new GameObject(name, typeof(RectTransform), typeof(LayoutElement));
        row.transform.SetParent(parent, false);
        row.layer = LayerMask.NameToLayer("UI");

        LayoutElement le = row.GetComponent<LayoutElement>();
        le.preferredHeight = height;
        le.flexibleWidth = 1;

        return row;
    }

    static GameObject CreateSlider(string name, Transform parent)
    {
        // Create slider root
        GameObject sliderObj = new GameObject(name, typeof(RectTransform), typeof(Slider));
        sliderObj.transform.SetParent(parent, false);
        sliderObj.layer = LayerMask.NameToLayer("UI");

        Slider slider = sliderObj.GetComponent<Slider>();
        slider.minValue = 0;
        slider.maxValue = 1;
        slider.value = 1;

        // Background
        GameObject bg = new GameObject("Background", typeof(RectTransform), typeof(CanvasRenderer), typeof(Image));
        bg.transform.SetParent(sliderObj.transform, false);
        bg.layer = LayerMask.NameToLayer("UI");
        RectTransform bgRT = bg.GetComponent<RectTransform>();
        bgRT.anchorMin = new Vector2(0, 0.25f);
        bgRT.anchorMax = new Vector2(1, 0.75f);
        bgRT.sizeDelta = Vector2.zero;
        Image bgImg = bg.GetComponent<Image>();
        bgImg.color = new Color(0.25f, 0.25f, 0.3f, 1f);
        bgImg.sprite = AssetDatabase.GetBuiltinExtraResource<Sprite>("UI/Skin/Background.psd");
        bgImg.type = Image.Type.Sliced;

        // Fill Area
        GameObject fillArea = new GameObject("Fill Area", typeof(RectTransform));
        fillArea.transform.SetParent(sliderObj.transform, false);
        fillArea.layer = LayerMask.NameToLayer("UI");
        RectTransform fillAreaRT = fillArea.GetComponent<RectTransform>();
        fillAreaRT.anchorMin = new Vector2(0, 0.25f);
        fillAreaRT.anchorMax = new Vector2(1, 0.75f);
        fillAreaRT.offsetMin = new Vector2(5, 0);
        fillAreaRT.offsetMax = new Vector2(-15, 0);

        // Fill
        GameObject fill = new GameObject("Fill", typeof(RectTransform), typeof(CanvasRenderer), typeof(Image));
        fill.transform.SetParent(fillArea.transform, false);
        fill.layer = LayerMask.NameToLayer("UI");
        RectTransform fillRT = fill.GetComponent<RectTransform>();
        fillRT.anchorMin = Vector2.zero;
        fillRT.anchorMax = Vector2.one;
        fillRT.sizeDelta = new Vector2(10, 0);
        Image fillImg = fill.GetComponent<Image>();
        fillImg.color = new Color(0.3f, 0.6f, 0.8f, 1f);
        fillImg.sprite = AssetDatabase.GetBuiltinExtraResource<Sprite>("UI/Skin/UISprite.psd");
        fillImg.type = Image.Type.Sliced;

        // Handle Slide Area
        GameObject handleArea = new GameObject("Handle Slide Area", typeof(RectTransform));
        handleArea.transform.SetParent(sliderObj.transform, false);
        handleArea.layer = LayerMask.NameToLayer("UI");
        RectTransform handleAreaRT = handleArea.GetComponent<RectTransform>();
        handleAreaRT.anchorMin = Vector2.zero;
        handleAreaRT.anchorMax = Vector2.one;
        handleAreaRT.offsetMin = new Vector2(10, 0);
        handleAreaRT.offsetMax = new Vector2(-10, 0);

        // Handle
        GameObject handle = new GameObject("Handle", typeof(RectTransform), typeof(CanvasRenderer), typeof(Image));
        handle.transform.SetParent(handleArea.transform, false);
        handle.layer = LayerMask.NameToLayer("UI");
        RectTransform handleRT = handle.GetComponent<RectTransform>();
        handleRT.sizeDelta = new Vector2(20, 0);
        handleRT.anchorMin = new Vector2(0, 0);
        handleRT.anchorMax = new Vector2(0, 1);
        Image handleImg = handle.GetComponent<Image>();
        handleImg.color = new Color(0.9f, 0.9f, 0.9f, 1f);
        handleImg.sprite = AssetDatabase.GetBuiltinExtraResource<Sprite>("UI/Skin/Knob.psd");

        // Wire slider
        slider.fillRect = fillRT;
        slider.handleRect = handleRT;
        slider.targetGraphic = handleImg;

        return sliderObj;
    }

    static GameObject CreateDropdown(string name, Transform parent)
    {
        // Create dropdown root
        GameObject ddObj = new GameObject(name, typeof(RectTransform), typeof(CanvasRenderer), typeof(Image), typeof(TMP_Dropdown));
        ddObj.transform.SetParent(parent, false);
        ddObj.layer = LayerMask.NameToLayer("UI");

        Image ddImg = ddObj.GetComponent<Image>();
        ddImg.color = new Color(0.25f, 0.25f, 0.35f, 1f);
        ddImg.sprite = AssetDatabase.GetBuiltinExtraResource<Sprite>("UI/Skin/UISprite.psd");
        ddImg.type = Image.Type.Sliced;

        TMP_Dropdown dropdown = ddObj.GetComponent<TMP_Dropdown>();

        // Label
        GameObject labelObj = CreateTextObject("Label", ddObj.transform, "Alto", 16, TextAlignmentOptions.Left, Color.white);
        RectTransform labelRT = labelObj.GetComponent<RectTransform>();
        labelRT.anchorMin = Vector2.zero;
        labelRT.anchorMax = Vector2.one;
        labelRT.offsetMin = new Vector2(10, 2);
        labelRT.offsetMax = new Vector2(-30, -2);

        // Arrow
        GameObject arrowObj = new GameObject("Arrow", typeof(RectTransform), typeof(CanvasRenderer), typeof(Image));
        arrowObj.transform.SetParent(ddObj.transform, false);
        arrowObj.layer = LayerMask.NameToLayer("UI");
        RectTransform arrowRT = arrowObj.GetComponent<RectTransform>();
        arrowRT.anchorMin = new Vector2(1, 0);
        arrowRT.anchorMax = new Vector2(1, 1);
        arrowRT.pivot = new Vector2(1, 0.5f);
        arrowRT.sizeDelta = new Vector2(25, 0);
        arrowRT.anchoredPosition = new Vector2(-5, 0);
        Image arrowImg = arrowObj.GetComponent<Image>();
        arrowImg.color = new Color(0.8f, 0.8f, 0.8f, 1f);

        // Template
        GameObject template = new GameObject("Template", typeof(RectTransform), typeof(CanvasRenderer), typeof(Image), typeof(ScrollRect));
        template.transform.SetParent(ddObj.transform, false);
        template.layer = LayerMask.NameToLayer("UI");
        RectTransform templateRT = template.GetComponent<RectTransform>();
        templateRT.anchorMin = new Vector2(0, 0);
        templateRT.anchorMax = new Vector2(1, 0);
        templateRT.pivot = new Vector2(0.5f, 1);
        templateRT.sizeDelta = new Vector2(0, 150);
        templateRT.anchoredPosition = new Vector2(0, 2);

        Image templateImg = template.GetComponent<Image>();
        templateImg.color = new Color(0.2f, 0.2f, 0.3f, 1f);
        templateImg.sprite = AssetDatabase.GetBuiltinExtraResource<Sprite>("UI/Skin/UISprite.psd");
        templateImg.type = Image.Type.Sliced;

        ScrollRect scrollRect = template.GetComponent<ScrollRect>();
        scrollRect.horizontal = false;

        // Viewport
        GameObject viewport = new GameObject("Viewport", typeof(RectTransform), typeof(CanvasRenderer), typeof(Image), typeof(Mask));
        viewport.transform.SetParent(template.transform, false);
        viewport.layer = LayerMask.NameToLayer("UI");
        RectTransform viewportRT = viewport.GetComponent<RectTransform>();
        viewportRT.anchorMin = Vector2.zero;
        viewportRT.anchorMax = Vector2.one;
        viewportRT.sizeDelta = Vector2.zero;
        viewportRT.anchoredPosition = Vector2.zero;

        Image viewportImg = viewport.GetComponent<Image>();
        viewportImg.sprite = AssetDatabase.GetBuiltinExtraResource<Sprite>("UI/Skin/UIMask.psd");
        viewportImg.type = Image.Type.Sliced;

        Mask mask = viewport.GetComponent<Mask>();
        mask.showMaskGraphic = false;

        scrollRect.viewport = viewportRT;

        // Content
        GameObject content = new GameObject("Content", typeof(RectTransform));
        content.transform.SetParent(viewport.transform, false);
        content.layer = LayerMask.NameToLayer("UI");
        RectTransform contentRT = content.GetComponent<RectTransform>();
        contentRT.anchorMin = new Vector2(0, 1);
        contentRT.anchorMax = new Vector2(1, 1);
        contentRT.pivot = new Vector2(0.5f, 1);
        contentRT.sizeDelta = new Vector2(0, 28);
        contentRT.anchoredPosition = Vector2.zero;

        scrollRect.content = contentRT;

        // Item
        GameObject item = new GameObject("Item", typeof(RectTransform), typeof(CanvasRenderer), typeof(Image), typeof(Toggle));
        item.transform.SetParent(content.transform, false);
        item.layer = LayerMask.NameToLayer("UI");
        RectTransform itemRT = item.GetComponent<RectTransform>();
        itemRT.anchorMin = new Vector2(0, 0.5f);
        itemRT.anchorMax = new Vector2(1, 0.5f);
        itemRT.sizeDelta = new Vector2(0, 28);

        Image itemImg = item.GetComponent<Image>();
        itemImg.color = new Color(0.25f, 0.25f, 0.35f, 1f);

