        itemCheckRT.anchoredPosition = new Vector2(10, 0);
        Image itemCheckImg = itemCheck.GetComponent<Image>();
        itemCheckImg.sprite = AssetDatabase.GetBuiltinExtraResource<Sprite>("UI/Skin/Checkmark.psd");

        toggle.graphic = itemCheckImg;

        // Item Label
        GameObject itemLabel = CreateTextObject("Item Label", item.transform, "Option", 14, TextAlignmentOptions.Left, Color.white);
        RectTransform itemLabelRT = itemLabel.GetComponent<RectTransform>();
        itemLabelRT.anchorMin = Vector2.zero;
        itemLabelRT.anchorMax = Vector2.one;
        itemLabelRT.offsetMin = new Vector2(25, 1);
        itemLabelRT.offsetMax = new Vector2(-10, -2);

        // Wire dropdown
        dropdown.targetGraphic = ddImg;
        dropdown.template = templateRT;
        dropdown.captionText = labelObj.GetComponent<TextMeshProUGUI>();
        dropdown.itemText = itemLabel.GetComponent<TextMeshProUGUI>();

        // Add options
        dropdown.ClearOptions();
        dropdown.AddOptions(new System.Collections.Generic.List<string> { "Bajo", "Medio", "Alto" });
        dropdown.value = 2; // Alto by default

        template.SetActive(false);

        return ddObj;
    }
}

