using UnityEngine;
using UnityEngine.UI;
using UnityEditor;
using TMPro;

public class FixOptionsPanel
{
    [MenuItem("Tools/Fix Options Panel")]
    public static void Execute()
    {
        // Find the OptionsPanel
        GameObject optionsPanel = GameObject.Find("Canvas/OptionsPanel");
        if (optionsPanel == null)
        {
            // Try finding inactive
            Canvas canvas = Object.FindFirstObjectByType<Canvas>();
            if (canvas == null) { Debug.LogError("No Canvas found!"); return; }
            foreach (Transform child in canvas.transform)
            {
                if (child.name == "OptionsPanel")
                {
                    optionsPanel = child.gameObject;
                    break;
                }
            }
        }

        if (optionsPanel == null)
        {
            Debug.LogError("OptionsPanel not found!");
            return;
        }

        // Temporarily activate to find children
        bool wasActive = optionsPanel.activeSelf;
        optionsPanel.SetActive(true);

        // Delete old elements that are duplicates
        // Old: TabsBar (we have TabBar)
        DestroyChild(optionsPanel.transform, "TabsBar");
        // Old: PanelGeneral/VolumenMusica (we have VolumeRow)
        Transform panelGeneral = optionsPanel.transform.Find("PanelGeneral");
        if (panelGeneral != null)
        {
            DestroyChild(panelGeneral, "VolumenMusica");
            // Old BtnPantallaCompleta directly in PanelGeneral (we have FullscreenRow/BtnPantallaCompleta)
            Transform oldBtn = panelGeneral.Find("BtnPantallaCompleta");
            if (oldBtn != null)
            {
                // Check if it's the direct child (not inside FullscreenRow)
                Object.DestroyImmediate(oldBtn.gameObject);
                Debug.Log("Deleted old BtnPantallaCompleta from PanelGeneral");
            }
        }

        // Old TitleText at root of OptionsPanel (we have our own TitleText)
        // Check if there are duplicate TitleTexts
        int titleCount = 0;
        foreach (Transform child in optionsPanel.transform)
        {
            if (child.name == "TitleText") titleCount++;
        }
        // Keep only one - the script created one, so if there were already one, remove the old
        // The old one would be first
        if (titleCount > 1)
        {
            foreach (Transform child in optionsPanel.transform)
            {
                if (child.name == "TitleText")
                {
                    // Check if it's the old one (no specific way, just remove first found if duplicate)
                    // Actually let's just keep the situation as is - only one TitleText was created by our script
                    break;
                }
            }
        }

        // Now wire up the OptionsManager to the NEW elements
        OptionsManager om = optionsPanel.GetComponent<OptionsManager>();
        if (om == null)
        {
            Debug.LogError("OptionsManager not found on OptionsPanel!");
            optionsPanel.SetActive(wasActive);
            return;
        }

        // Find new elements
        Transform tabBar = optionsPanel.transform.Find("TabBar");
        Transform fullscreenRow = panelGeneral != null ? panelGeneral.Find("FullscreenRow") : null;
        Transform volumeRow = panelGeneral != null ? panelGeneral.Find("VolumeRow") : null;
        Transform graphicsRow = panelGeneral != null ? panelGeneral.Find("GraphicsRow") : null;
        Transform panelControles = optionsPanel.transform.Find("PanelControles");
        Transform btnCerrar = optionsPanel.transform.Find("BtnCerrar");

        if (tabBar != null)
        {
            Transform btnGeneral = tabBar.Find("BtnGeneral");
            Transform btnControles = tabBar.Find("BtnControles");
            if (btnGeneral != null) om.btnGeneral = btnGeneral.GetComponent<Button>();
            if (btnControles != null) om.btnControles = btnControles.GetComponent<Button>();
        }

        if (panelGeneral != null) om.panelGeneral = panelGeneral.gameObject;
        if (panelControles != null) om.panelControles = panelControles.gameObject;

        if (fullscreenRow != null)
        {
            Transform btnFS = fullscreenRow.Find("BtnPantallaCompleta");
            if (btnFS != null) om.btnPantallaCompleta = btnFS.GetComponent<Button>();
        }

        if (volumeRow != null)
        {
            Transform slider = volumeRow.Find("SliderVolumen");
            if (slider != null) om.sliderVolumen = slider.GetComponent<Slider>();
        }

        if (graphicsRow != null)
        {
            Transform dropdown = graphicsRow.Find("DropdownGraficos");
            if (dropdown != null) om.dropdownGraficos = dropdown.GetComponent<TMP_Dropdown>();
        }

        if (btnCerrar != null) om.btnCerrar = btnCerrar.GetComponent<Button>();

        // Restore active state
        optionsPanel.SetActive(false);

        EditorUtility.SetDirty(om);
        EditorUtility.SetDirty(optionsPanel);
        UnityEditor.SceneManagement.EditorSceneManager.MarkSceneDirty(
            UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene());

        Debug.Log("Options Panel fixed and wired up successfully!");
        Debug.Log($"btnGeneral: {(om.btnGeneral != null ? om.btnGeneral.name : "NULL")}");
        Debug.Log($"btnControles: {(om.btnControles != null ? om.btnControles.name : "NULL")}");
        Debug.Log($"btnPantallaCompleta: {(om.btnPantallaCompleta != null ? om.btnPantallaCompleta.name : "NULL")}");
        Debug.Log($"sliderVolumen: {(om.sliderVolumen != null ? om.sliderVolumen.name : "NULL")}");
        Debug.Log($"dropdownGraficos: {(om.dropdownGraficos != null ? om.dropdownGraficos.name : "NULL")}");
        Debug.Log($"btnCerrar: {(om.btnCerrar != null ? om.btnCerrar.name : "NULL")}");
    }

    static void DestroyChild(Transform parent, string childName)
    {
        Transform child = parent.Find(childName);
        if (child != null)
        {
            Object.DestroyImmediate(child.gameObject);
            Debug.Log($"Deleted old element: {childName}");
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using UnityEditor;
using TMPro;
using System.Collections.Generic;

public class RebuildOptionsPanel
{
    [MenuItem("Tools/Rebuild Options Panel")]
    public static void Execute()
    {
        // Find Canvas
        Canvas canvas = Object.FindFirstObjectByType<Canvas>();
        if (canvas == null) { Debug.LogError("No Canvas found!"); return; }

        // Delete existing OptionsPanel (even if inactive)
        foreach (Transform child in canvas.transform)
        {
            if (child.name == "OptionsPanel")
            {
                Object.DestroyImmediate(child.gameObject);
                Debug.Log("Deleted existing OptionsPanel");
                break;
            }
        }

        // ===== CREATE OPTIONS PANEL =====
        GameObject optionsPanel = new GameObject("OptionsPanel", typeof(RectTransform), typeof(CanvasRenderer), typeof(Image), typeof(OptionsManager));
        optionsPanel.transform.SetParent(canvas.transform, false);
        optionsPanel.layer = LayerMask.NameToLayer("UI");

        RectTransform optionsRT = optionsPanel.GetComponent<RectTransform>();
        optionsRT.anchorMin = new Vector2(0.5f, 0.5f);
        optionsRT.anchorMax = new Vector2(0.5f, 0.5f);
        optionsRT.pivot = new Vector2(0.5f, 0.5f);
        optionsRT.sizeDelta = new Vector2(700, 500);
        optionsRT.anchoredPosition = Vector2.zero;

        Image optionsBg = optionsPanel.GetComponent<Image>();
        optionsBg.color = new Color(0.06f, 0.06f, 0.09f, 0.95f);
        optionsBg.sprite = AssetDatabase.GetBuiltinExtraResource<Sprite>("UI/Skin/UISprite.psd");
        optionsBg.type = Image.Type.Sliced;

        // ===== TITLE =====
        GameObject titleObj = CreateText("TitleText", optionsPanel.transform, "OPCIONES", 30, TextAlignmentOptions.Center, Color.white, FontStyles.Bold);
        SetAnchors(titleObj, new Vector2(0, 1), new Vector2(1, 1), new Vector2(0.5f, 1));
        titleObj.GetComponent<RectTransform>().sizeDelta = new Vector2(0, 50);
        titleObj.GetComponent<RectTransform>().anchoredPosition = new Vector2(0, -10);

        // ===== CLOSE BUTTON (X) =====
        GameObject btnCerrar = CreateButton("BtnCerrar", optionsPanel.transform, "X", new Color(0.7f, 0.15f, 0.15f, 1f));
        RectTransform cerrarRT = btnCerrar.GetComponent<RectTransform>();
        cerrarRT.anchorMin = new Vector2(1, 1);
        cerrarRT.anchorMax = new Vector2(1, 1);
        cerrarRT.pivot = new Vector2(1, 1);
        cerrarRT.sizeDelta = new Vector2(45, 45);
        cerrarRT.anchoredPosition = new Vector2(-8, -8);
        btnCerrar.GetComponentInChildren<TextMeshProUGUI>().fontSize = 22;
        btnCerrar.GetComponentInChildren<TextMeshProUGUI>().fontStyle = FontStyles.Bold;

        // ===== TAB BAR =====
        GameObject tabBar = new GameObject("TabBar", typeof(RectTransform), typeof(HorizontalLayoutGroup));
        tabBar.transform.SetParent(optionsPanel.transform, false);
        tabBar.layer = LayerMask.NameToLayer("UI");
        SetAnchors(tabBar, new Vector2(0, 1), new Vector2(1, 1), new Vector2(0.5f, 1));
        tabBar.GetComponent<RectTransform>().sizeDelta = new Vector2(-60, 40);
        tabBar.GetComponent<RectTransform>().anchoredPosition = new Vector2(0, -65);

        HorizontalLayoutGroup tabHLG = tabBar.GetComponent<HorizontalLayoutGroup>();
        tabHLG.spacing = 5;
        tabHLG.childForceExpandWidth = true;
        tabHLG.childForceExpandHeight = true;
        tabHLG.childAlignment = TextAnchor.MiddleCenter;

        GameObject btnGeneral = CreateButton("BtnGeneral", tabBar.transform, "General", new Color(0.2f, 0.5f, 0.6f, 1f));
        GameObject btnControles = CreateButton("BtnControles", tabBar.transform, "Controles", new Color(0.15f, 0.15f, 0.15f, 1f));

        // ===== PANEL GENERAL =====
        GameObject panelGeneral = new GameObject("PanelGeneral", typeof(RectTransform), typeof(VerticalLayoutGroup));
        panelGeneral.transform.SetParent(optionsPanel.transform, false);
        panelGeneral.layer = LayerMask.NameToLayer("UI");
        RectTransform pgRT = panelGeneral.GetComponent<RectTransform>();
        pgRT.anchorMin = Vector2.zero;
        pgRT.anchorMax = Vector2.one;
        pgRT.pivot = new Vector2(0.5f, 0.5f);
        pgRT.offsetMin = new Vector2(30, 60);
        pgRT.offsetMax = new Vector2(-30, -115);

        VerticalLayoutGroup pgVLG = panelGeneral.GetComponent<VerticalLayoutGroup>();
        pgVLG.spacing = 20;
        pgVLG.padding = new RectOffset(10, 10, 15, 10);
        pgVLG.childAlignment = TextAnchor.UpperCenter;
        pgVLG.childForceExpandWidth = true;
        pgVLG.childForceExpandHeight = false;

        // --- Fullscreen Button ---
        GameObject fsRow = CreateRow("FullscreenRow", panelGeneral.transform, 50);
        GameObject btnFullscreen = CreateButton("BtnPantallaCompleta", fsRow.transform, "Pantalla Completa: ON", new Color(0.2f, 0.35f, 0.5f, 1f));
        StretchFill(btnFullscreen);

        // --- Volume Row ---
        GameObject volRow = CreateRow("VolumeRow", panelGeneral.transform, 55);

        GameObject volLabel = CreateText("VolumenLabel", volRow.transform, "Volumen", 20, TextAlignmentOptions.Left, Color.white, FontStyles.Normal);
        RectTransform vlRT = volLabel.GetComponent<RectTransform>();
        vlRT.anchorMin = new Vector2(0, 0);
        vlRT.anchorMax = new Vector2(0.28f, 1);
        vlRT.offsetMin = new Vector2(5, 0);
        vlRT.offsetMax = Vector2.zero;

        GameObject sliderObj = CreateSlider("SliderVolumen", volRow.transform);
        RectTransform slRT = sliderObj.GetComponent<RectTransform>();
        slRT.anchorMin = new Vector2(0.30f, 0.2f);
        slRT.anchorMax = new Vector2(0.98f, 0.8f);
        slRT.sizeDelta = Vector2.zero;
        slRT.anchoredPosition = Vector2.zero;

        // --- Graphics Row ---
        GameObject gfxRow = CreateRow("GraphicsRow", panelGeneral.transform, 55);

        GameObject gfxLabel = CreateText("GraficosLabel", gfxRow.transform, "Gráficos", 20, TextAlignmentOptions.Left, Color.white, FontStyles.Normal);
        RectTransform glRT = gfxLabel.GetComponent<RectTransform>();
        glRT.anchorMin = new Vector2(0, 0);
        glRT.anchorMax = new Vector2(0.28f, 1);
        glRT.offsetMin = new Vector2(5, 0);
        glRT.offsetMax = Vector2.zero;

        GameObject dropdownObj = CreateDropdown("DropdownGraficos", gfxRow.transform);
        RectTransform ddRT = dropdownObj.GetComponent<RectTransform>();
        ddRT.anchorMin = new Vector2(0.30f, 0.1f);
        ddRT.anchorMax = new Vector2(0.98f, 0.9f);
        ddRT.sizeDelta = Vector2.zero;
        ddRT.anchoredPosition = Vector2.zero;

        // ===== PANEL CONTROLES =====
        GameObject panelControles = new GameObject("PanelControles", typeof(RectTransform), typeof(VerticalLayoutGroup));
        panelControles.transform.SetParent(optionsPanel.transform, false);
        panelControles.layer = LayerMask.NameToLayer("UI");
        RectTransform pcRT = panelControles.GetComponent<RectTransform>();
        pcRT.anchorMin = Vector2.zero;
        pcRT.anchorMax = Vector2.one;
        pcRT.pivot = new Vector2(0.5f, 0.5f);
        pcRT.offsetMin = new Vector2(30, 60);
        pcRT.offsetMax = new Vector2(-30, -115);

        VerticalLayoutGroup pcVLG = panelControles.GetComponent<VerticalLayoutGroup>();
        pcVLG.spacing = 10;
        pcVLG.padding = new RectOffset(15, 15, 20, 10);
        pcVLG.childAlignment = TextAnchor.UpperCenter;
        pcVLG.childForceExpandWidth = true;
        pcVLG.childForceExpandHeight = false;

        GameObject ctrlText = CreateText("ControlsInfo", panelControles.transform,
            "Controles del juego:\n\nClick izquierdo - Seleccionar carta\nClick derecho - Cancelar",
            18, TextAlignmentOptions.TopLeft, new Color(0.8f, 0.8f, 0.8f, 1f), FontStyles.Normal);
        LayoutElement ctLE = ctrlText.AddComponent<LayoutElement>();
        ctLE.preferredHeight = 200;

        panelControles.SetActive(false);

        // ===== WIRE UP OptionsManager =====
        OptionsManager om = optionsPanel.GetComponent<OptionsManager>();
        om.panelGeneral = panelGeneral;
        om.panelControles = panelControles;
        om.btnGeneral = btnGeneral.GetComponent<Button>();
        om.btnControles = btnControles.GetComponent<Button>();
        om.btnPantallaCompleta = btnFullscreen.GetComponent<Button>();
        om.sliderVolumen = sliderObj.GetComponent<Slider>();
        om.dropdownGraficos = dropdownObj.GetComponent<TMP_Dropdown>();
        om.btnCerrar = btnCerrar.GetComponent<Button>();

        // ===== WIRE UP MainMenuManager =====
        MainMenuManager mmm = Object.FindFirstObjectByType<MainMenuManager>();
        if (mmm != null)
        {
            mmm.optionsPanel = optionsPanel;
            EditorUtility.SetDirty(mmm);
        }

        // Wire OptionsButton onClick -> MainMenuManager.OnOptionsPressed
        GameObject optionsButton = GameObject.Find("Canvas/LeftPanel/OptionsButton");
        if (optionsButton != null && mmm != null)
        {
            Button optBtn = optionsButton.GetComponent<Button>();
            // Clear existing listeners
            UnityEditor.Events.UnityEventTools.AddVoidPersistentListener(
                optBtn.onClick,
                new UnityEngine.Events.UnityAction(mmm.OnOptionsPressed));
            EditorUtility.SetDirty(optBtn);
        }

        // Start inactive
        optionsPanel.SetActive(false);

        // Mark dirty
        EditorUtility.SetDirty(optionsPanel);
        UnityEditor.SceneManagement.EditorSceneManager.MarkSceneDirty(
            UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene());

        Debug.Log("Options Panel rebuilt successfully!");
        Debug.Log($"btnGeneral: {om.btnGeneral?.name}");
        Debug.Log($"btnControles: {om.btnControles?.name}");
        Debug.Log($"btnPantallaCompleta: {om.btnPantallaCompleta?.name}");
        Debug.Log($"sliderVolumen: {om.sliderVolumen?.name}");
        Debug.Log($"dropdownGraficos: {om.dropdownGraficos?.name}");
        Debug.Log($"btnCerrar: {om.btnCerrar?.name}");
    }

    static void SetAnchors(GameObject go, Vector2 min, Vector2 max, Vector2 pivot)
    {
        RectTransform rt = go.GetComponent<RectTransform>();
        rt.anchorMin = min;
        rt.anchorMax = max;
        rt.pivot = pivot;
    }

    static void StretchFill(GameObject go)
    {
        RectTransform rt = go.GetComponent<RectTransform>();
        rt.anchorMin = Vector2.zero;
        rt.anchorMax = Vector2.one;
        rt.sizeDelta = Vector2.zero;
        rt.anchoredPosition = Vector2.zero;
    }

    static GameObject CreateButton(string name, Transform parent, string text, Color bgColor)
    {
        GameObject btnObj = new GameObject(name, typeof(RectTransform), typeof(CanvasRenderer), typeof(Image), typeof(Button));
        btnObj.transform.SetParent(parent, false);
        btnObj.layer = LayerMask.NameToLayer("UI");

        Image img = btnObj.GetComponent<Image>();
        img.color = bgColor;
        img.sprite = AssetDatabase.GetBuiltinExtraResource<Sprite>("UI/Skin/UISprite.psd");
        img.type = Image.Type.Sliced;

        Button btn = btnObj.GetComponent<Button>();
        btn.targetGraphic = img;
        ColorBlock cb = btn.colors;
        cb.normalColor = Color.white;
        cb.highlightedColor = new Color(0.85f, 0.85f, 0.85f, 1f);
        cb.pressedColor = new Color(0.65f, 0.65f, 0.65f, 1f);
        btn.colors = cb;

        GameObject textObj = CreateText("Text (TMP)", btnObj.transform, text, 18, TextAlignmentOptions.Center, Color.white, FontStyles.Normal);
        StretchFill(textObj);

        return btnObj;
    }

    static GameObject CreateText(string name, Transform parent, string text, int fontSize, TextAlignmentOptions alignment, Color color, FontStyles style)
    {
        GameObject textObj = new GameObject(name, typeof(RectTransform), typeof(CanvasRenderer), typeof(TextMeshProUGUI));
        textObj.transform.SetParent(parent, false);
        textObj.layer = LayerMask.NameToLayer("UI");

        TextMeshProUGUI tmp = textObj.GetComponent<TextMeshProUGUI>();
        tmp.text = text;
        tmp.fontSize = fontSize;
        tmp.alignment = alignment;
        tmp.color = color;
        tmp.fontStyle = style;

        TMP_FontAsset font = Resources.Load<TMP_FontAsset>("Fonts & Materials/LiberationSans SDF");
