    static GameObject MakeRow(string name, Transform parent, float height)
    {
        GameObject row = new GameObject(name, typeof(RectTransform), typeof(LayoutElement));
        row.transform.SetParent(parent, false);
        row.layer = LayerMask.NameToLayer("UI");
        row.GetComponent<LayoutElement>().preferredHeight = height;
        row.GetComponent<LayoutElement>().flexibleWidth = 1;
        return row;
    }

    static GameObject MakeText(string name, Transform parent, string text, int fontSize, TextAlignmentOptions align, Color color, FontStyles style)
    {
        GameObject obj = new GameObject(name, typeof(RectTransform), typeof(CanvasRenderer), typeof(TextMeshProUGUI));
        obj.transform.SetParent(parent, false);
        obj.layer = LayerMask.NameToLayer("UI");
        TextMeshProUGUI tmp = obj.GetComponent<TextMeshProUGUI>();
        tmp.text = text;
        tmp.fontSize = fontSize;
        tmp.alignment = align;
        tmp.color = color;
        tmp.fontStyle = style;
        tmp.overflowMode = TextOverflowModes.Ellipsis;
        tmp.enableWordWrapping = false;
        TMP_FontAsset font = Resources.Load<TMP_FontAsset>("Fonts & Materials/LiberationSans SDF");
        if (font != null) tmp.font = font;
        return obj;
    }

    static GameObject MakeButton(string name, Transform parent, string text, Color bgColor, int fontSize, FontStyles style)
    {
        GameObject btnObj = new GameObject(name, typeof(RectTransform), typeof(CanvasRenderer), typeof(Image), typeof(Button));
        btnObj.transform.SetParent(parent, false);
        btnObj.layer = LayerMask.NameToLayer("UI");

        Image img = btnObj.GetComponent<Image>();
        img.color = bgColor;
        img.sprite = AssetDatabase.GetBuiltinExtraResource<Sprite>("UI/Skin/UISprite.psd");
        img.type = Image.Type.Sliced;

        Button btn = btnObj.GetComponent<Button>();
        btn.targetGraphic = img;
        ColorBlock cb = btn.colors;
        cb.normalColor = Color.white;
        cb.highlightedColor = new Color(0.85f, 0.85f, 0.85f, 1f);
        cb.pressedColor = new Color(0.65f, 0.65f, 0.65f, 1f);
        btn.colors = cb;

        GameObject textObj = MakeText("Text (TMP)", btnObj.transform, text, fontSize, TextAlignmentOptions.Center, Color.white, style);
        textObj.GetComponent<TextMeshProUGUI>().enableWordWrapping = false;
        Stretch(textObj);

        return btnObj;
    }

