using UnityEngine;
using UnityEngine.UI;
using UnityEditor;
using TMPro;
using System.Collections.Generic;

public class RebuildOptionsPanel
{
    [MenuItem("Tools/Rebuild Options Panel")]
    public static void Execute()
    {
        Canvas canvas = Object.FindFirstObjectByType<Canvas>();
        if (canvas == null) { Debug.LogError("No Canvas found!"); return; }

        // Delete existing OptionsPanel(s)
        List<GameObject> toDelete = new List<GameObject>();
        foreach (Transform child in canvas.transform)
        {
            if (child.name == "OptionsPanel")
                toDelete.Add(child.gameObject);
        }
        foreach (var go in toDelete)
            Object.DestroyImmediate(go);

        // ===== OPTIONS PANEL (dark overlay) =====
        GameObject panel = new GameObject("OptionsPanel", typeof(RectTransform), typeof(CanvasRenderer), typeof(Image), typeof(OptionsManager));
        panel.transform.SetParent(canvas.transform, false);
        panel.layer = 5;
        // Stretch to fill 70% of screen centered
        RectTransform pRT = panel.GetComponent<RectTransform>();
        pRT.anchorMin = new Vector2(0.15f, 0.08f);
        pRT.anchorMax = new Vector2(0.85f, 0.92f);
        pRT.offsetMin = Vector2.zero;
        pRT.offsetMax = Vector2.zero;
        Image pImg = panel.GetComponent<Image>();
        pImg.color = new Color(0.07f, 0.07f, 0.11f, 0.97f);
        pImg.sprite = AssetDatabase.GetBuiltinExtraResource<Sprite>("UI/Skin/UISprite.psd");
        pImg.type = Image.Type.Sliced;

        // ===== TITLE =====
        GameObject title = Txt("TitleText", panel.transform, "OPCIONES", 36, FontStyles.Bold, TextAlignmentOptions.Center);
        AnchorStretchTop(title, 70f, 5f);

        // ===== CLOSE BUTTON (X) =====
        GameObject btnCerrar = Btn("BtnCerrar", panel.transform, "X", new Color(0.65f, 0.12f, 0.12f, 1f), 24, FontStyles.Bold);
        RectTransform cRT = btnCerrar.GetComponent<RectTransform>();
        cRT.anchorMin = new Vector2(1, 1);
        cRT.anchorMax = new Vector2(1, 1);
        cRT.pivot = new Vector2(1, 1);
        cRT.sizeDelta = new Vector2(55, 55);
        cRT.anchoredPosition = new Vector2(-10, -10);

        // ===== TAB BAR =====
        GameObject tabBar = new GameObject("TabBar", typeof(RectTransform), typeof(HorizontalLayoutGroup));
        tabBar.transform.SetParent(panel.transform, false);
        tabBar.layer = 5;
        AnchorStretchTop(tabBar, 50f, 80f);
        RectTransform tbRT = tabBar.GetComponent<RectTransform>();
        tbRT.offsetMin = new Vector2(50, tbRT.offsetMin.y);
        tbRT.offsetMax = new Vector2(-50, tbRT.offsetMax.y);
        HorizontalLayoutGroup tbHLG = tabBar.GetComponent<HorizontalLayoutGroup>();
        tbHLG.spacing = 10;
        tbHLG.childForceExpandWidth = true;
        tbHLG.childForceExpandHeight = true;

        GameObject btnGeneral = Btn("BtnGeneral", tabBar.transform, "General", new Color(0.2f, 0.5f, 0.6f, 1f), 22, FontStyles.Normal);
        GameObject btnControles = Btn("BtnControles", tabBar.transform, "Controles", new Color(0.15f, 0.15f, 0.15f, 1f), 22, FontStyles.Normal);

        // ===== CONTENT AREA (below tabs, above bottom margin) =====
        // We'll use a content container that stretches between tabs and bottom
        GameObject contentArea = new GameObject("ContentArea", typeof(RectTransform));
        contentArea.transform.SetParent(panel.transform, false);
        contentArea.layer = 5;
        RectTransform caRT = contentArea.GetComponent<RectTransform>();
        caRT.anchorMin = Vector2.zero;
        caRT.anchorMax = Vector2.one;
        caRT.offsetMin = new Vector2(50, 30);   // left, bottom
        caRT.offsetMax = new Vector2(-50, -140); // right, top (below tabs)

        // ===== PANEL GENERAL =====
        GameObject panelGeneral = new GameObject("PanelGeneral", typeof(RectTransform));
        panelGeneral.transform.SetParent(contentArea.transform, false);
        panelGeneral.layer = 5;
        StretchFull(panelGeneral);

        // Row 1: Fullscreen button - centered, wide
        GameObject btnFS = Btn("BtnPantallaCompleta", panelGeneral.transform, "Pantalla Completa: ON", new Color(0.2f, 0.35f, 0.5f, 1f), 22, FontStyles.Normal);
        RectTransform fsRT = btnFS.GetComponent<RectTransform>();
        fsRT.anchorMin = new Vector2(0.1f, 0.78f);
        fsRT.anchorMax = new Vector2(0.9f, 0.93f);
        fsRT.offsetMin = Vector2.zero;
        fsRT.offsetMax = Vector2.zero;

        // Row 2: Volume label + slider
        GameObject volLabel = Txt("VolumenLabel", panelGeneral.transform, "Volumen", 24, FontStyles.Normal, TextAlignmentOptions.MidlineLeft);
        RectTransform vlRT = volLabel.GetComponent<RectTransform>();
        vlRT.anchorMin = new Vector2(0.05f, 0.55f);
        vlRT.anchorMax = new Vector2(0.25f, 0.72f);
        vlRT.offsetMin = Vector2.zero;
        vlRT.offsetMax = Vector2.zero;

        GameObject slider = MakeSlider("SliderVolumen", panelGeneral.transform);
        RectTransform slRT = slider.GetComponent<RectTransform>();
        slRT.anchorMin = new Vector2(0.28f, 0.57f);
        slRT.anchorMax = new Vector2(0.9f, 0.70f);
        slRT.offsetMin = Vector2.zero;
        slRT.offsetMax = Vector2.zero;

        // Row 3: Graphics label + dropdown
        GameObject gfxLabel = Txt("GraficosLabel", panelGeneral.transform, "Gráficos", 24, FontStyles.Normal, TextAlignmentOptions.MidlineLeft);
        RectTransform glRT = gfxLabel.GetComponent<RectTransform>();
        glRT.anchorMin = new Vector2(0.05f, 0.32f);
        glRT.anchorMax = new Vector2(0.25f, 0.49f);
        glRT.offsetMin = Vector2.zero;
        glRT.offsetMax = Vector2.zero;

        GameObject dropdown = MakeDropdown("DropdownGraficos", panelGeneral.transform);
        RectTransform ddRT = dropdown.GetComponent<RectTransform>();
        ddRT.anchorMin = new Vector2(0.28f, 0.33f);
        ddRT.anchorMax = new Vector2(0.65f, 0.48f);
        ddRT.offsetMin = Vector2.zero;
        ddRT.offsetMax = Vector2.zero;

        // ===== PANEL CONTROLES =====
        GameObject panelControles = new GameObject("PanelControles", typeof(RectTransform));
        panelControles.transform.SetParent(contentArea.transform, false);
        panelControles.layer = 5;
        StretchFull(panelControles);

        GameObject ctrlText = Txt("ControlsInfo", panelControles.transform,
            "Controles del juego:\n\nClick izquierdo - Seleccionar carta\nClick derecho - Cancelar",
            22, FontStyles.Normal, TextAlignmentOptions.TopLeft);
        ctrlText.GetComponent<TextMeshProUGUI>().enableWordWrapping = true;
        ctrlText.GetComponent<TextMeshProUGUI>().color = new Color(0.8f, 0.8f, 0.8f, 1f);
        RectTransform ctRT = ctrlText.GetComponent<RectTransform>();
        ctRT.anchorMin = new Vector2(0.05f, 0.1f);
        ctRT.anchorMax = new Vector2(0.95f, 0.95f);
        ctRT.offsetMin = Vector2.zero;
        ctRT.offsetMax = Vector2.zero;

        panelControles.SetActive(false);

        // ===== WIRE OptionsManager =====
        OptionsManager om = panel.GetComponent<OptionsManager>();
        om.panelGeneral = panelGeneral;
        om.panelControles = panelControles;
        om.btnGeneral = btnGeneral.GetComponent<Button>();
        om.btnControles = btnControles.GetComponent<Button>();
        om.btnPantallaCompleta = btnFS.GetComponent<Button>();
        om.sliderVolumen = slider.GetComponent<Slider>();
        om.dropdownGraficos = dropdown.GetComponent<TMP_Dropdown>();
        om.btnCerrar = btnCerrar.GetComponent<Button>();

        // ===== WIRE MainMenuManager =====
        MainMenuManager mmm = Object.FindFirstObjectByType<MainMenuManager>();
        if (mmm != null)
        {
            mmm.optionsPanel = panel;
            EditorUtility.SetDirty(mmm);
        }

        // Start inactive
        panel.SetActive(false);

        EditorUtility.SetDirty(panel);
        UnityEditor.SceneManagement.EditorSceneManager.MarkSceneDirty(
            UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene());

        Debug.Log("Options Panel rebuilt OK!");
        Debug.Log($"refs: general={om.btnGeneral?.name}, controles={om.btnControles?.name}, fs={om.btnPantallaCompleta?.name}, slider={om.sliderVolumen?.name}, dd={om.dropdownGraficos?.name}, cerrar={om.btnCerrar?.name}");
    }

    // ========== HELPERS ==========

    static void StretchFull(GameObject go)
    {
        RectTransform rt = go.GetComponent<RectTransform>();
        rt.anchorMin = Vector2.zero;
        rt.anchorMax = Vector2.one;
        rt.offsetMin = Vector2.zero;
        rt.offsetMax = Vector2.zero;
    }

    static void AnchorStretchTop(GameObject go, float height, float topOffset)
    {
        RectTransform rt = go.GetComponent<RectTransform>();
        rt.anchorMin = new Vector2(0, 1);
        rt.anchorMax = new Vector2(1, 1);
        rt.pivot = new Vector2(0.5f, 1);
        rt.offsetMin = new Vector2(0, 0);
        rt.offsetMax = new Vector2(0, 0);
        rt.sizeDelta = new Vector2(0, height);
        rt.anchoredPosition = new Vector2(0, -topOffset);
    }

    static GameObject Txt(string name, Transform parent, string text, int fontSize, FontStyles style, TextAlignmentOptions align)
    {
        GameObject obj = new GameObject(name, typeof(RectTransform), typeof(CanvasRenderer), typeof(TextMeshProUGUI));
        obj.transform.SetParent(parent, false);
        obj.layer = 5;
        TextMeshProUGUI tmp = obj.GetComponent<TextMeshProUGUI>();
        tmp.text = text;
        tmp.fontSize = fontSize;
        tmp.fontStyle = style;
        tmp.alignment = align;
        tmp.color = Color.white;
        tmp.enableWordWrapping = false;
        tmp.overflowMode = TextOverflowModes.Overflow;
        TMP_FontAsset font = Resources.Load<TMP_FontAsset>("Fonts & Materials/LiberationSans SDF");
        if (font != null) tmp.font = font;
        return obj;
    }

