        arrow.GetComponent<TextMeshProUGUI>().color = new Color(0.7f, 0.7f, 0.7f);
        RectTransform arRT = arrow.GetComponent<RectTransform>();
        arRT.anchorMin = new Vector2(1, 0);
        arRT.anchorMax = new Vector2(1, 1);
        arRT.pivot = new Vector2(1, 0.5f);
        arRT.sizeDelta = new Vector2(30, 0);
        arRT.anchoredPosition = new Vector2(-5, 0);

        // Template
        GameObject template = new GameObject("Template", typeof(RectTransform), typeof(CanvasRenderer), typeof(Image), typeof(ScrollRect));
        template.transform.SetParent(ddObj.transform, false);
        template.layer = 5;
        RectTransform tRT = template.GetComponent<RectTransform>();
        tRT.anchorMin = new Vector2(0, 0);
        tRT.anchorMax = new Vector2(1, 0);
        tRT.pivot = new Vector2(0.5f, 1);
        tRT.sizeDelta = new Vector2(0, 150);
        tRT.anchoredPosition = new Vector2(0, 2);
        Image tImg = template.GetComponent<Image>();
        tImg.color = new Color(0.12f, 0.12f, 0.2f, 1f);
        tImg.sprite = AssetDatabase.GetBuiltinExtraResource<Sprite>("UI/Skin/UISprite.psd");
        tImg.type = Image.Type.Sliced;
        ScrollRect sr = template.GetComponent<ScrollRect>();
        sr.horizontal = false;

        // Viewport
        GameObject viewport = new GameObject("Viewport", typeof(RectTransform), typeof(CanvasRenderer), typeof(Image), typeof(Mask));
        viewport.transform.SetParent(template.transform, false);
        viewport.layer = 5;
        StretchFull(viewport);
        Image vpImg = viewport.GetComponent<Image>();
        vpImg.sprite = AssetDatabase.GetBuiltinExtraResource<Sprite>("UI/Skin/UIMask.psd");
        vpImg.type = Image.Type.Sliced;
        viewport.GetComponent<Mask>().showMaskGraphic = false;
        sr.viewport = viewport.GetComponent<RectTransform>();

        // Content
        GameObject content = new GameObject("Content", typeof(RectTransform));
        content.transform.SetParent(viewport.transform, false);
        content.layer = 5;
        RectTransform cRT = content.GetComponent<RectTransform>();
        cRT.anchorMin = new Vector2(0, 1);
        cRT.anchorMax = new Vector2(1, 1);
        cRT.pivot = new Vector2(0.5f, 1);
        cRT.sizeDelta = new Vector2(0, 28);
        sr.content = cRT;

        // Item
        GameObject item = new GameObject("Item", typeof(RectTransform), typeof(CanvasRenderer), typeof(Image), typeof(Toggle));
        item.transform.SetParent(content.transform, false);
        item.layer = 5;
        RectTransform iRT = item.GetComponent<RectTransform>();
        iRT.anchorMin = new Vector2(0, 0.5f);
        iRT.anchorMax = new Vector2(1, 0.5f);
        iRT.sizeDelta = new Vector2(0, 35);
        Image iImg = item.GetComponent<Image>();
        iImg.color = new Color(0.18f, 0.18f, 0.28f, 1f);
        Toggle toggle = item.GetComponent<Toggle>();
        toggle.targetGraphic = iImg;

        GameObject itemBg = new GameObject("Item Background", typeof(RectTransform), typeof(CanvasRenderer), typeof(Image));
        itemBg.transform.SetParent(item.transform, false);
        itemBg.layer = 5;
        StretchFull(itemBg);
        itemBg.GetComponent<Image>().color = new Color(0.25f, 0.45f, 0.65f, 1f);

        GameObject itemCheck = new GameObject("Item Checkmark", typeof(RectTransform), typeof(CanvasRenderer), typeof(Image));
        itemCheck.transform.SetParent(item.transform, false);
        itemCheck.layer = 5;
        RectTransform icRT = itemCheck.GetComponent<RectTransform>();
        icRT.anchorMin = new Vector2(0, 0.5f);
        icRT.anchorMax = new Vector2(0, 0.5f);
        icRT.sizeDelta = new Vector2(20, 20);
        icRT.anchoredPosition = new Vector2(10, 0);
        Image icImg = itemCheck.GetComponent<Image>();
        icImg.sprite = AssetDatabase.GetBuiltinExtraResource<Sprite>("UI/Skin/Checkmark.psd");
        toggle.graphic = icImg;

        GameObject itemLabel = Txt("Item Label", item.transform, "Option", 18, FontStyles.Normal, TextAlignmentOptions.MidlineLeft);
        RectTransform ilRT = itemLabel.GetComponent<RectTransform>();
        ilRT.anchorMin = Vector2.zero;
        ilRT.anchorMax = Vector2.one;
        ilRT.offsetMin = new Vector2(30, 1);
        ilRT.offsetMax = new Vector2(-10, -2);

        dropdown.targetGraphic = ddImg;
        dropdown.template = tRT;
        dropdown.captionText = label.GetComponent<TextMeshProUGUI>();
        dropdown.itemText = itemLabel.GetComponent<TextMeshProUGUI>();
        dropdown.ClearOptions();
        dropdown.AddOptions(new List<string> { "Bajo", "Medio", "Alto" });
        dropdown.value = 2;

        template.SetActive(false);
        return ddObj;
    }
}

