using UnityEngine;
using UnityEngine.UI;
using UnityEditor;

public class FixTabBar
{
    public static void Execute()
    {
        // Find OptionsPanel (it's active right now for screenshot)
        Canvas canvas = Object.FindFirstObjectByType<Canvas>();
        if (canvas == null) return;

        Transform optionsPanel = null;
        foreach (Transform child in canvas.transform)
        {
            if (child.name == "OptionsPanel")
            {
                optionsPanel = child;
                break;
            }
        }
        if (optionsPanel == null) { Debug.LogError("OptionsPanel not found"); return; }

        // Fix panel background to be fully opaque
        Image panelImg = optionsPanel.GetComponent<Image>();
        panelImg.color = new Color(0.07f, 0.07f, 0.11f, 1f);

        // Fix TabBar
        Transform tabBar = optionsPanel.Find("TabBar");
        if (tabBar != null)
        {
            HorizontalLayoutGroup hlg = tabBar.GetComponent<HorizontalLayoutGroup>();
            hlg.childControlWidth = true;
            hlg.childControlHeight = true;
            hlg.childForceExpandWidth = true;
            hlg.childForceExpandHeight = true;

            // Widen the tab bar - reduce side margins
            RectTransform tbRT = tabBar.GetComponent<RectTransform>();
            tbRT.offsetMin = new Vector2(40, tbRT.offsetMin.y);
            tbRT.offsetMax = new Vector2(-40, tbRT.offsetMax.y);

            Debug.Log("TabBar fixed: childControlWidth/Height enabled");
        }

        EditorUtility.SetDirty(optionsPanel.gameObject);
        UnityEditor.SceneManagement.EditorSceneManager.MarkSceneDirty(
            UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene());

        Debug.Log("Fixes applied!");
    }
}
